import{t as e}from"./apiClient-CdSaRFMD.js";var t={login:async t=>e.post(`/Auth/Login`,{Email:t.Email,Password:t.Password}),register:async t=>(await e.post(`/Auth/Register`,t)).data,confirmEmail:async t=>(await e.post(`/Auth/Confirm-Email`,t)).data,forgotPassword:async t=>(await e.post(`/Auth/Forgot-Password`,t)).data,resetPassword:async t=>(await e.post(`/Auth/Reset-Password`,t)).data,googleLogin:async t=>(await e.post(`/Auth/Google-login`,t)).data,resendOtp:async t=>(await e.post(`/Auth/resend-otp`,{email:t})).data,logout:async()=>(await e.post(`/Auth/logout`)).data};export{t};